"use client";

import { useSession } from "next-auth/react";
import { Nav } from "./Nav";

export default function AuthWrapper({ children }) {

  const { data: session, status } = useSession();

  if (status === "loading") {
    return null;
  }

  return (
    <>
      {session && <Nav />}
      {children}
    </>
  );
}